try {
/* module-key = 'com.stiltsoft.confluence.evernote.evernote-integration:ztinymce-insert-evernote-resources', location = 'js/editor-plugin-src.js' */
(function($) {

    AJS.Rte.BootstrapManager.addTinyMcePluginInit(function (settings) {
        settings.plugins += ",insertevernote";
        settings.theme_advanced_buttons2 += ",insertevernote";
    });

    (function(tinymce) {

        tinymce.create('tinymce.plugins.InsertEvernotePlugin', {

            init:function(ed) {

                $('#evernote-insert-link').click(function (evt) {
                    evt.stopPropagation();
                    evt.preventDefault();
                    $('#rte-button-insert').click();
                    showDialog();
                });

                var dialog;

                window.EvernoteInserter = {
                    insert:function(noteGuid, isBusiness) {
                        loadNote(noteGuid, isBusiness, ed, dialog);
                    }
                };

                var showDialog = function() {
                    var tileOuterWidth = 202;
                    var scrollWidth = getScrollWidth();
                    var count = Math.floor(($(window).width() - scrollWidth - 20)/tileOuterWidth);
                    if (count > 6) {
                        count = 6;
                    }
                    dialog = new AJS.Dialog({
                        width: (tileOuterWidth * count) + scrollWidth + 20,
                        height: $(window).height()*0.7,
                        id:"evernote-dialog",
                        closeOnOutsideClick:true
                    });
                    dialog.show();
                    EvernoteDialog.create(dialog, false);
                };
            },

            getInfo:function() {
                return {
                    longname: 'Insert Evernote',
                    author: 'StiltSoft',
                    authorurl: 'http://stiltsoft.com',
                    infourl: 'http://stiltsoft.com/',
                    version: "1.0"
                };
            }
        });

        // Register plugin
        tinymce.PluginManager.add('insertevernote', tinymce.plugins.InsertEvernotePlugin);

    })(tinymce);

    function getScrollWidth() {
        var div = document.createElement('div');
        div.style.overflowY = 'scroll';
        div.style.width = '50px';
        div.style.height = '50px';
        div.style.visibility = 'hidden';

        $('body').append(div);
        var scrollWidth = div.offsetWidth - div.clientWidth;
        $(div).remove();
        return scrollWidth;
    }

})(AJS.$);
}catch(e){WRMCB(e)};
